    "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Get a free hosted Postgres database in seconds: `npx create-db`\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n//////////////////////////\n// ENUMS (🔥 EVITA ERROS)\n//////////////////////////\n\nenum RecipeSource {\n  user\n  external\n}\n\nenum SubmissionStatus {\n  pending\n  processed\n}\n\nenum Visibility {\n  private\n  public\n}\n\nenum NotificationType {\n  follow\n  like\n  comment\n\n  // 🔥 SISTEMA\n  system\n  ai_result\n  fraud_alert\n  badge\n}\n\n//////////////////////////\n// 👤 USER\n//////////////////////////\n\nmodel User {\n  id        String   @id @default(uuid())\n  name      String\n  email     String   @unique\n  password  String\n  avatar    String?\n  createdAt DateTime @default(now())\n\n  // 🔥 CONTADORES (performance)\n  followersCount Int @default(0)\n  followingCount Int @default(0)\n\n  // 🎮 GAMIFICAÇÃO\n  level      Int     @default(1)\n  experience Int     @default(0)\n  badges     Badge[]\n\n  // RELAÇÕES\n  recipes     Recipe[]\n  submissions RecipeSubmission[]\n  comments    Comment[]\n  likes       Like[]\n\n  refreshTokens RefreshToken[]\n\n  followers Follow[] @relation(\"followers\")\n  following Follow[] @relation(\"following\")\n\n  notifications     Notification[] @relation(\"UserNotifications\")\n  sentNotifications Notification[] @relation(\"NotificationSender\")\n\n  @@index([email])\n}\n\nmodel RefreshToken {\n  id        String   @id @default(uuid())\n  token     String   @unique\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  @@index([userId])\n  @@index([expiresAt])\n}\n\n//////////////////////////\n// 🔗 FOLLOW\n//////////////////////////\n\nmodel Follow {\n  id String @id @default(uuid())\n\n  followerId  String\n  followingId String\n\n  follower  User @relation(\"following\", fields: [followerId], references: [id], onDelete: Cascade)\n  following User @relation(\"followers\", fields: [followingId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n\n  @@unique([followerId, followingId])\n}\n\n//////////////////////////\n// 🔔 NOTIFICAÇÕES (CORRIGIDO)\n//////////////////////////\n\nmodel Notification {\n  id        String           @id @default(uuid())\n  type      NotificationType\n  content   String?\n  read      Boolean          @default(false)\n  createdAt DateTime         @default(now())\n\n  // 👤 quem recebe\n  userId String\n  user   User   @relation(\"UserNotifications\", fields: [userId], references: [id], onDelete: Cascade)\n\n  // 👤 quem gerou (pode ser null = sistema)\n  senderId String?\n  sender   User?   @relation(\"NotificationSender\", fields: [senderId], references: [id])\n\n  // 🔗 contexto (opcional)\n  submissionId String?\n  submission   RecipeSubmission? @relation(fields: [submissionId], references: [id])\n\n  // 🧠 FLAG IMPORTANTE\n  isSystem Boolean @default(false)\n\n  @@index([userId])\n  @@index([read])\n  @@index([isSystem])\n}\n\n//////////////////////////\n// 🍲 RECIPE\n//////////////////////////\n\nmodel Recipe {\n  id          String  @id @default(uuid())\n  title       String\n  description String?\n  imageUrl    String?\n  category    String?\n  difficulty  String?\n\n  source     RecipeSource\n  externalId String?\n  cachedAt   DateTime?\n\n  createdAt DateTime @default(now())\n\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id])\n\n  ingredients Ingredient[]\n  steps       Step[]\n  submissions RecipeSubmission[]\n\n  @@index([title])\n  @@index([externalId])\n}\n\n//////////////////////////\n// 🥕 INGREDIENTES\n//////////////////////////\n\nmodel Ingredient {\n  id       String  @id @default(uuid())\n  name     String\n  quantity String?\n\n  recipeId String\n  recipe   Recipe @relation(fields: [recipeId], references: [id], onDelete: Cascade)\n}\n\n//////////////////////////\n// 🧾 PASSOS (FIX)\n//////////////////////////\n\nmodel Step {\n  id      String @id @default(uuid())\n  order   Int\n  content String\n\n  recipeId String\n  recipe   Recipe @relation(fields: [recipeId], references: [id], onDelete: Cascade)\n\n  @@unique([recipeId, order]) // 🔥 evita duplicação\n}\n\n//////////////////////////\n// 📸 SUBMISSÃO\n//////////////////////////\n\nmodel RecipeSubmission {\n  id       String @id @default(uuid())\n  imageUrl String\n\n  score    Float?\n  feedback String?\n  isFraud  Boolean          @default(false)\n  status   SubmissionStatus @default(pending)\n\n  caption    String?\n  visibility Visibility @default(private)\n\n  likesCount    Int @default(0)\n  commentsCount Int @default(0)\n\n  createdAt DateTime @default(now())\n\n  userId   String\n  recipeId String\n\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  recipe Recipe @relation(fields: [recipeId], references: [id], onDelete: Cascade)\n\n  comments      Comment[]\n  likes         Like[]\n  notifications Notification[]\n\n  @@index([visibility])\n  @@index([status])\n}\n\n//////////////////////////\n// 💬 COMENTÁRIOS\n//////////////////////////\n\nmodel Comment {\n  id        String   @id @default(uuid())\n  content   String\n  createdAt DateTime @default(now())\n\n  userId       String\n  submissionId String\n\n  user       User             @relation(fields: [userId], references: [id], onDelete: Cascade)\n  submission RecipeSubmission @relation(fields: [submissionId], references: [id], onDelete: Cascade)\n\n  @@index([submissionId])\n}\n\n//////////////////////////\n// ❤️ LIKES\n//////////////////////////\n\nmodel Like {\n  id String @id @default(uuid())\n\n  userId       String\n  submissionId String\n\n  user       User             @relation(fields: [userId], references: [id], onDelete: Cascade)\n  submission RecipeSubmission @relation(fields: [submissionId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, submissionId])\n}\n\n//////////////////////////\n// 🏆 BADGES\n//////////////////////////\n\nmodel Badge {\n  id          String   @id @default(uuid())\n  name        String\n  description String?\n  iconUrl     String?\n  unlockedAt  DateTime @default(now())\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n}\n",
